/* ─────────────────────────────────────────────────────
   AI LEARNING ENGINE
   Learns from user input: tracks key usage, song names,
   most common selections, typing patterns
───────────────────────────────────────────────────── */
const AI = {
  STORE_KEY: 'uecsa_ai_v2',

  data: {
    keyCounts:    {},   // key -> number of times used
    songNames:    {},   // lowercase partial -> [{name,count}]
    sectionKeys:  {},   // section id -> most common key
    recentOrders: [],   // last 10 mass orders
    keyBySeason:  {},   // season -> most common key
    totalInputs:  0,
  },

  load() {
    try {
      const raw = localStorage.getItem(this.STORE_KEY);
      if (raw) this.data = { ...this.data, ...JSON.parse(raw) };
    } catch(e) {}
  },

  save() {
    try { localStorage.setItem(this.STORE_KEY, JSON.stringify(this.data)); } catch(e) {}
  },

  recordKey(key, sectionId, season) {
    if (!key) return;
    this.data.keyCounts[key] = (this.data.keyCounts[key]||0) + 1;
    if (sectionId) this.data.sectionKeys[sectionId] = key;
    if (season && key) {
      if (!this.data.keyBySeason[season]) this.data.keyBySeason[season] = {};
      this.data.keyBySeason[season][key] = (this.data.keyBySeason[season][key]||0) + 1;
    }
    this.data.totalInputs++;
    this.save();
  },

  recordSongName(name, sectionId) {
    if (!name || name.length < 2) return;
    const key = name.toLowerCase().slice(0,4);
    if (!this.data.songNames[key]) this.data.songNames[key] = [];
    const existing = this.data.songNames[key].find(x => x.n === name);
    if (existing) existing.c++;
    else this.data.songNames[key].push({n: name, c: 1});
    this.save();
  },

  suggestKeys(sectionId, season, limit = 4) {
    const suggestions = new Set();
    // Section-specific suggestion
    if (sectionId && this.data.sectionKeys[sectionId]) suggestions.add(this.data.sectionKeys[sectionId]);
    // Season-based
    if (season && this.data.keyBySeason[season]) {
      const seasonKeys = Object.entries(this.data.keyBySeason[season]).sort((a,b)=>b[1]-a[1]);
      seasonKeys.slice(0,2).forEach(([k]) => suggestions.add(k));
    }
    // Overall most used
    const topKeys = Object.entries(this.data.keyCounts).sort((a,b)=>b[1]-a[1]).slice(0,5);
    topKeys.forEach(([k]) => suggestions.add(k));
    // Fallback popular keys
    ['G mjr','D mjr','C mjr','A mjr','Bb mjr','F mjr'].forEach(k => suggestions.add(k));
    return [...suggestions].slice(0, limit);
  },

  suggestSongNames(partial, limit = 6) {
    if (!partial || partial.length < 2) return [];
    const key = partial.toLowerCase().slice(0,4);
    const matches = [];
    for (const [, entries] of Object.entries(this.data.songNames)) {
      entries.forEach(e => {
        if (e.n.toLowerCase().includes(partial.toLowerCase())) matches.push(e);
      });
    }
    return matches.sort((a,b)=>b.c-a.c).slice(0,limit).map(e=>e.n);
  },

  recordOrder(orderData) {
    this.data.recentOrders.unshift({ ...orderData, ts: Date.now() });
    if (this.data.recentOrders.length > 20) this.data.recentOrders.pop();
    this.save();
  },
};

