let $fb = null;
let $fbAuth = null, $fbDb = null, $fbStorage = null;
let $fbOnline = false;

async function initFirebase() {
  try {
    const v = '10.12.0';
    const base = `https://www.gstatic.com/firebasejs/${v}`;
    const [appM, authM, fsM, stM] = await Promise.all([
      import(`${base}/firebase-app.js`),
      import(`${base}/firebase-auth.js`),
      import(`${base}/firebase-firestore.js`),
      import(`${base}/firebase-storage.js`),
    ]);
    const app = appM.initializeApp(FB_CONFIG);
    $fbAuth    = authM.getAuth(app);
    $fbDb      = fsM.getFirestore(app);
    $fbStorage = stM.getStorage(app);
    $fb = { ...authM, ...fsM, ...stM };
    $fbOnline = true;
    console.log('[UECSA] Firebase connected ✓');
  } catch(e) {
    console.log('[UECSA] Firebase offline, using local storage only');
    $fbOnline = false;
  }
}

