function showPage(id) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.getElementById('page-' + id).classList.add('active');
}

function switchView(id) {
  document.querySelectorAll('.view').forEach(v => v.classList.remove('active-view'));
  const el = document.getElementById('view-' + id);
  if (el) el.classList.add('active-view');
  $currentView = id;
  const renders = {
    home: renderHome, scores: renderScores,
    announcements: renderAnnouncements, chat: renderChat,
    about: renderAbout,
  };
  if (renders[id]) renders[id]();
}

function toast(msg, type = 'ok') {
  const el = document.getElementById('toast-el');
  el.textContent = msg; el.className = 'show ' + type;
  clearTimeout($toastTimer);
  $toastTimer = setTimeout(() => el.className = '', 3200);
}

function esc(s = '') { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function ini(n = '') { return n.trim().split(/\s+/).map(w=>w[0]||'').join('').slice(0,2).toUpperCase()||'?'; }

function fmtTime(ts) {
  if (!ts) return '';
  const d = new Date(ts);
  return d.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'});
}
function timeAgo(ts) {
  if (!ts) return '';
  const s = (Date.now() - ts) / 1000;
  if (s < 60)    return 'sasa hivi';
  if (s < 3600)  return Math.floor(s/60) + 'm';
  if (s < 86400) return Math.floor(s/3600) + 'h';
  const d = new Date(ts);
  return d.toLocaleDateString('sw-KE', {day:'numeric', month:'short'});
}

function openModal(id) { document.getElementById(id).classList.add('open'); }
