/* ─────────────────────────────────────────────────────
   LOGIN
───────────────────────────────────────────────────── */
function doLogin() {
  const userVal = document.getElementById('l-user').value.trim();
  const passVal = document.getElementById('l-pass').value;
  const errEl   = document.getElementById('login-err');
  const btn     = document.getElementById('btn-login');
  errEl.textContent = '';

  if (!userVal) return errEl.textContent = 'Weka jina la mtumiaji au barua pepe.';
  if (!passVal) return errEl.textContent = 'Weka neno la siri.';

  btn.disabled = true; btn.querySelector('span').textContent = 'Inaingia…';

  // Check owner offline login
  if ((userVal.toLowerCase() === OWNER.username.toLowerCase() || userVal === OWNER.username) && passVal === OWNER.password) {
    $user = { ...OWNER, isOwner: true };
    if (document.getElementById('l-remember').checked) {
      localStorage.setItem('uecsa_session', JSON.stringify({ uid: OWNER.uid, ts: Date.now() }));
    }
    afterLogin();
    return;
  }

  // Check local director accounts
  const db = DB.get();
  const dir = db.directors.find(d =>
    (d.username?.toLowerCase() === userVal.toLowerCase() || d.name?.toLowerCase() === userVal.toLowerCase() || d.email?.toLowerCase() === userVal.toLowerCase())
    && d.password === passVal
  );

  if (dir) {
    $user = { ...dir, isOwner: false };
    if (document.getElementById('l-remember').checked) {
      localStorage.setItem('uecsa_session', JSON.stringify({ uid: dir.uid, ts: Date.now() }));
    }
    DB.update(d => {
      const u = d.directors.find(x=>x.uid===dir.uid);
      if (u) u.lastSeen = Date.now();
    });
    afterLogin();
    return;
  }

  // Try Firebase if online
  if ($fbOnline && $fbAuth) {
    $fbAuth.signInWithEmailAndPassword($fbAuth, userVal, passVal)
      .then(cred => {
        return $fb.getDoc($fb.doc($fbDb,'users',cred.user.uid)).then(snap => {
          $user = snap.exists() ? { ...snap.data(), uid: cred.user.uid } : { uid: cred.user.uid, name: userVal, role: 'director' };
          afterLogin();
        });
      })
      .catch(e => {
        btn.disabled = false; btn.querySelector('span').textContent = 'Ingia';
        errEl.textContent = 'Jina la mtumiaji au neno la siri si sahihi.';
      });
    return;
  }

  btn.disabled = false; btn.querySelector('span').textContent = 'Ingia';
  errEl.textContent = 'Jina la mtumiaji au neno la siri si sahihi.';
}

function afterLogin() {
  DB.logActivity(`${$user.name} ameingia`, '🔐', $user.uid);
  setupDashboard();
  showPage('dashboard');
  document.getElementById('btn-login').disabled = false;
  document.getElementById('btn-login').querySelector('span').textContent = 'Ingia';
}

function doLogout() {
  DB.logActivity(`${$user?.name} ametoka`, '👋', $user?.uid);
  localStorage.removeItem('uecsa_session');
  $user = null;
  clearInterval($gcInterval);
  showPage('login');
  document.getElementById('l-user').value = '';
  document.getElementById('l-pass').value = '';
  document.getElementById('login-err').textContent = '';
}

// Auto-login from saved session
function checkAutoLogin() {
  try {
    const sess = JSON.parse(localStorage.getItem('uecsa_session') || 'null');
    if (!sess) return false;
    // Owner session
    if (sess.uid === OWNER.uid) {
      $user = { ...OWNER, isOwner: true };
      setupDashboard(); showPage('dashboard'); return true;
    }
    // Director session
    const db = DB.get();
    const dir = db.directors.find(d => d.uid === sess.uid);
    if (dir) {
      $user = { ...dir, isOwner: false };
      setupDashboard(); showPage('dashboard'); return true;
    }
  } catch(e) {}
  return false;
}

