function roleLabel(r) {
  const m = {owner:'Mmiliki',chief:'Msimamizi Mkuu',deputy:'Naibu',director:'Msimamizi',organist:'Mpiga Ogani',conductor:'Kondakta',member:'Mwanachama'};
  return m[r] || r || '—';
}

function updateStats() {
  const db = DB.get();
  setElText('stat-directors', db.directors.length);
  setElText('stat-scores', db.scores.length);
  setElText('stat-orders', db.massOrders.length);
  const unread = db.groupMessages.filter(m => m.uid !== $user?.uid && !m.readBy?.includes($user?.uid)).length;
  setElText('stat-msgs', unread || db.groupMessages.length);
  if (unread > 0) { setElHtml('chat-badge', unread); document.getElementById('chat-badge').style.display=''; }
}

