function renderOwnerActivity() {
  const db = DB.get();
  const el = document.getElementById('activity-list'); if(!el) return;
  if (!db.activity.length) { el.innerHTML='<div class="empty-state"><span class="ei-icon">📋</span><p>Hakuna shughuli bado.</p></div>'; return; }
  el.innerHTML = db.activity.slice(0,15).map((a,i) => `
    <div class="act-item" style="animation-delay:${i*.04}s">
      <span class="act-ic">${a.icon}</span>
      <div class="act-info">
        <div class="act-msg">${esc(a.msg)}</div>
        <div class="act-time">${timeAgo(a.time)}</div>
      </div>
    </div>`).join('');

  // Owner panel
  setElHtml('op-today-activity', db.activity.slice(0,5).map(a=>`<div style="font-size:12px;padding:4px 0;border-bottom:1px solid var(--border)">${a.icon} ${esc(a.msg)} <span style="color:var(--muted);font-size:10px;">${timeAgo(a.time)}</span></div>`).join(''));
  const online = db.directors.filter(d=>d.online).map(d=>d.name).join(', ') || 'Hakuna';
  setElText('op-online-users', online);
}

/* ─────────────────────────────────────────────────────
   GLOBAL SEARCH
───────────────────────────────────────────────────── */
function globalSearch(q) {
  const res = document.getElementById('search-results');
  if (!q || q.length < 2) { res.style.display='none'; return; }
  const db = DB.get();
  const items = [];
  q = q.toLowerCase();
  db.scores.forEach(s => { if((s.title||'').toLowerCase().includes(q)||(s.author||'').toLowerCase().includes(q)||(s.key||'').toLowerCase().includes(q)) items.push({icon:'🎵',type:'Wimbo',name:`${s.title} — ${s.author} (${s.key})`}); });
  db.directors.forEach(d => { if((d.name||'').toLowerCase().includes(q)) items.push({icon:'👤',type:'Msimamizi',name:`${d.name} (${roleLabel(d.role)})`}); });
  db.announcements.forEach(a => { if((a.title||'').toLowerCase().includes(q)||(a.body||'').toLowerCase().includes(q)) items.push({icon:'📢',type:'Tangazo',name:a.title}); });
  db.massOrders.forEach(m => { if((m.occasion||'').toLowerCase().includes(q)||(m.season||'').toLowerCase().includes(q)) items.push({icon:'📄',type:'Mwongozo',name:`${m.occasion||m.season||'Mwongozo'} — ${new Date(m.savedAt).toLocaleDateString()}`}); });

  if (!items.length) { res.innerHTML='<div style="padding:16px;text-align:center;color:var(--muted);font-size:13px;">Hakuna matokeo.</div>'; res.style.display='block'; return; }
  res.innerHTML = items.slice(0,10).map(i=>`<div class="sr-item"><span>${i.icon}</span><div><div class="sr-type">${esc(i.type)}</div><div class="sr-name">${esc(i.name)}</div></div></div>`).join('');
  res.style.display='block';
}

