/* ─────────────────────────────────────────────────────
   SCORES (MUSIC LIBRARY)
───────────────────────────────────────────────────── */
function renderScores() {
  const db = DB.get();
  // Build filter options
  const keyFilter  = document.getElementById('scores-key-filter');
  const typeFilter = document.getElementById('scores-type-filter');
  if (keyFilter.options.length <= 1) {
    const keys  = [...new Set(db.scores.map(s=>s.key).filter(Boolean))].sort();
    const types = [...new Set(db.scores.map(s=>s.type).filter(Boolean))].sort();
    keys.forEach(k => { const o=document.createElement('option'); o.value=o.textContent=k; keyFilter.appendChild(o); });
    types.forEach(t => { const o=document.createElement('option'); o.value=o.textContent=t; typeFilter.appendChild(o); });
  }
  filterScores();
}

function filterScores() {
  const q     = (document.getElementById('scores-search')?.value||'').toLowerCase();
  const key   = document.getElementById('scores-key-filter')?.value||'';
  const type  = document.getElementById('scores-type-filter')?.value||'';
  const db    = DB.get();
  let scores  = db.scores;
  if (q)    scores = scores.filter(s=>(s.title||'').toLowerCase().includes(q)||(s.author||'').toLowerCase().includes(q)||(s.key||'').toLowerCase().includes(q)||(s.type||'').toLowerCase().includes(q));
  if (key)  scores = scores.filter(s=>s.key===key);
  if (type) scores = scores.filter(s=>s.type===type);
  const el = document.getElementById('scores-grid'); if(!el) return;
  if (!scores.length) { el.innerHTML=`<div class="empty-state" style="grid-column:1/-1;"><span class="ei-icon">🎵</span><p>Hakuna nyimbo zilizohifadhiwa bado. Ongeza ya kwanza!</p></div>`; return; }
  el.innerHTML = scores.map((s,i)=>`
    <div class="score-card" style="animation-delay:${i*.04}s" onclick="viewScore('${s.id}')">
      <div class="score-card-top">
        <span class="key-pill">${esc(s.key)}</span>
        <span class="type-pill">${esc(s.type)}</span>
      </div>
      <div class="score-title">${esc(s.title)}</div>
      <div class="score-author">na ${esc(s.author)}</div>
      ${s.notes?`<div class="score-notes">${esc(s.notes)}</div>`:''}
      <div class="score-footer">
        <span class="score-uploader">↑ ${esc(s.addedBy||'—')}</span>
        ${s.pdfData?`<button class="btn btn-blue btn-xs" onclick="event.stopPropagation();openScorePdf('${s.id}')">📄 PDF</button>`:''}
      </div>
    </div>`).join('');
}

function viewScore(id) {
  const db = DB.get();
  const s = db.scores.find(x=>x.id===id); if(!s) return;
  // Simple view modal
  const modal = document.createElement('div');
  modal.className = 'modal-bg open';
  modal.innerHTML = `<div class="modal" style="max-width:600px;">
    <button class="modal-x" onclick="this.closest('.modal-bg').remove()">×</button>
    <h3>${esc(s.title)}</h3>
    <div style="display:flex;gap:8px;margin-bottom:14px;"><span class="key-pill" style="padding:5px 12px;font-size:12px;">${esc(s.key)}</span><span class="type-pill" style="padding:5px 12px;font-size:12px;">${esc(s.type)}</span></div>
    <div style="font-size:14px;margin-bottom:8px;"><strong>Mtunzi:</strong> ${esc(s.author)}</div>
    ${s.notes?`<div style="color:var(--muted);font-size:13px;margin-bottom:12px;">${esc(s.notes)}</div>`:''}
    <div style="font-size:12px;color:var(--muted);margin-bottom:16px;">Iliongezwa na ${esc(s.addedBy||'—')} · ${timeAgo(s.addedAt)}</div>
    ${s.pdfData?`<button class="btn btn-blue" onclick="openScorePdf('${s.id}')" style="margin-bottom:12px;">📄 Fungua PDF</button>`:''}
    ${($user.isOwner||$user.role==='owner'||$user.role==='chief')?`<button class="btn btn-danger btn-sm" onclick="deleteScore('${s.id}');this.closest('.modal-bg').remove()" style="margin-left:8px;">Futa</button>`:''}
  </div>`;
  document.body.appendChild(modal);
}

function openScorePdf(id) {
  const db = DB.get();
  const s = db.scores.find(x=>x.id===id); if(!s||!s.pdfData) return;
  const win = window.open('','_blank');
  win.document.write(`<html><body style="margin:0;background:#000;"><iframe src="${s.pdfData}" style="width:100%;height:100vh;border:none;"></iframe></body></html>`);
}

function deleteScore(id) {
  DB.update(d => { d.scores = d.scores.filter(s=>s.id!==id); });
  toast('Wimbo umefutwa.','info'); renderScores();
}

function openAddScoreModal() {
  // Populate selects
  const keyEl  = document.getElementById('sc-key');
  const typeEl = document.getElementById('sc-type');
  if (keyEl.options.length <= 1) MUSICAL_KEYS.forEach(k=>{const o=document.createElement('option');o.value=o.textContent=k;keyEl.appendChild(o);});
  if (typeEl.options.length <= 1) SONG_TYPES.forEach(t=>{const o=document.createElement('option');o.value=o.textContent=t;typeEl.appendChild(o);});
  openModal('modal-score');
}

function sDzOver(e) { e.preventDefault(); document.getElementById('score-drop-zone').style.borderColor='var(--blue-l)'; }
function sDzLeave()  { document.getElementById('score-drop-zone').style.borderColor=''; }
function sDzDrop(e)  { e.preventDefault(); sDzLeave(); const f=e.dataTransfer.files[0]; if(f?.type==='application/pdf') { $scorePdfFile=f; document.getElementById('score-pdf-lbl').textContent='✓ '+f.name; } }
function scorePdfChosen(inp) { if(inp.files[0]) { $scorePdfFile=inp.files[0]; document.getElementById('score-pdf-lbl').textContent='✓ '+inp.files[0].name; } }

async function doAddScore() {
  const title = document.getElementById('sc-title').value.trim();
  const author= document.getElementById('sc-author').value.trim();
  const key   = document.getElementById('sc-key').value;
  const type  = document.getElementById('sc-type').value;
  const notes = document.getElementById('sc-notes').value.trim();
  const err   = document.getElementById('score-err');
  const btn   = document.getElementById('btn-add-score');
  err.textContent='';
  if (!title)  return err.textContent='Weka jina la wimbo.';
  if (!author) return err.textContent='Weka jina la mtunzi.';
  if (!key)    return err.textContent='Chagua ufunguo.';
  if (!type)   return err.textContent='Chagua aina.';
  btn.disabled=true; btn.textContent='Inahifadhi…';

  let pdfData = null;
  if ($scorePdfFile) {
    pdfData = await new Promise(res => {
      const r = new FileReader(); r.onload = e => res(e.target.result); r.readAsDataURL($scorePdfFile);
    });
  }

  const score = { id:'sc_'+Date.now(), title, author, key, type, notes, pdfData, addedBy:$user.name, addedByUid:$user.uid, addedAt:Date.now() };
  DB.update(d => { d.scores.unshift(score); });
  AI.recordKey(key, 'library', '');

  // Update filter options
  const keyFilter = document.getElementById('scores-key-filter');
  const typeFilter= document.getElementById('scores-type-filter');
  if (![...keyFilter.options].find(o=>o.value===key)) { const o=document.createElement('option');o.value=o.textContent=key;keyFilter.appendChild(o); }
  if (![...typeFilter.options].find(o=>o.value===type)) { const o=document.createElement('option');o.value=o.textContent=type;typeFilter.appendChild(o); }

  closeModal('modal-score');
  ['sc-title','sc-author','sc-notes'].forEach(i=>{const el=document.getElementById(i);if(el)el.value='';});
  document.getElementById('sc-key').value=''; document.getElementById('sc-type').value='';
  document.getElementById('score-pdf-lbl').textContent=''; $scorePdfFile=null;
  btn.disabled=false; btn.textContent='Hifadhi Wimbo';
  DB.logActivity(`${$user.name} aliongeza wimbo: "${title}"`, '🎵', $user.uid);
  toast('Wimbo umehifadhiwa!'); updateStats(); renderScores();
}

