/* ─────────────────────────────────────────────────────
   CHAT
───────────────────────────────────────────────────── */
let $currentChatThread = 'group';

function renderChat() {
  renderDMList();
  showGroupChat();
}

function renderDMList() {
  const db = DB.get();
  const el = document.getElementById('dm-list-items'); if(!el) return;
  const dirs = db.directors.filter(d=>d.uid!==$user.uid);
  el.innerHTML = dirs.map(d=>`
    <div class="csb-item" onclick="showDM('${d.uid}','${esc(d.name)}')">
      <div class="csbi-av" style="background:linear-gradient(135deg,var(--blue),var(--blue-l));">${ini(d.name)}</div>
      <div class="csbi-info">
        <div class="csbi-name">${esc(d.name)}</div>
        <div class="csbi-last">${esc(roleLabel(d.role))}</div>
      </div>
    </div>`).join('');
}

function showGroupChat() {
  $currentChatThread = 'group';
  document.querySelectorAll('.csb-item').forEach(i=>i.classList.remove('active'));
  document.querySelectorAll('.csb-item')[0]?.classList.add('active');
  const hbar = document.getElementById('chat-header-bar');
  const sub  = document.getElementById('chb-sub');
  const db   = DB.get();
  if (hbar) hbar.querySelector('.chb-av').textContent='K';
  if (hbar) hbar.querySelector('.chb-name').textContent='Kikundi — Wasimamizi Wote';
  if (sub)  sub.textContent = db.directors.length+' wasimamizi';
  renderMessages('group');
}

function showDM(uid, name) {
  $currentChatThread = uid;
  const hbar = document.getElementById('chat-header-bar');
  if (hbar) { hbar.querySelector('.chb-av').textContent=ini(name); hbar.querySelector('.chb-name').textContent=esc(name); }
  const db = DB.get();
  const dir = db.directors.find(d=>d.uid===uid);
  const sub = document.getElementById('chb-sub');
  if (sub) sub.textContent = dir ? roleLabel(dir.role) : 'Msimamizi';
  renderMessages(uid);
}

function renderMessages(thread) {
  const db = DB.get();
  const msgs = thread === 'group'
    ? db.groupMessages
    : (db.dmThreads[[[$user.uid,thread].sort().join('__')]] || []);
  const el = document.getElementById('chat-messages'); if(!el) return;
  if (!msgs.length) { el.innerHTML=`<div style="text-align:center;color:var(--muted);padding:50px;font-size:13px;">Hakuna ujumbe bado. Anza mazungumzo! 🎵</div>`; return; }
  el.innerHTML = msgs.map(m => {
    const out = m.uid === $user.uid;
    return `<div class="chat-bubble-wrap ${out?'outgoing':'incoming'}">
      ${!out?`<div class="chat-bubble-name">${esc(m.name)}</div>`:''}
      <div class="chat-bubble ${out?'bubble-out':'bubble-in'}">${esc(m.text)}</div>
      <div class="bubble-time">${fmtTime(m.ts)}</div>
    </div>`;
  }).join('');
  el.scrollTop = el.scrollHeight;
}

function sendMsg() {
  const inp = document.getElementById('chat-input');
  const txt = inp?.value.trim(); if (!txt) return;
  inp.value = '';
  const msg = { id:'msg_'+Date.now(), uid:$user.uid, name:$user.name, text:txt, ts:Date.now() };
  if ($currentChatThread === 'group') {
    DB.update(d => { d.groupMessages.push(msg); if(d.groupMessages.length>500) d.groupMessages.shift(); });
    setElText('gc-last-msg', txt);
  } else {
    const threadKey = [$user.uid,$currentChatThread].sort().join('__');
    DB.update(d => { if(!d.dmThreads[threadKey]) d.dmThreads[threadKey]=[]; d.dmThreads[threadKey].push(msg); });
  }
  renderMessages($currentChatThread);
}

function startChatRefresh() {
  clearInterval($gcInterval);
  $gcInterval = setInterval(() => {
    if ($currentView === 'chat') renderMessages($currentChatThread);
  }, 3000);
}

