function renderAbout() {
  const db = DB.get();
  // Directors list
  const el = document.getElementById('about-directors-list'); if(el) {
    const dirs = db.directors.filter(d=>d.role!=='member');
    el.innerHTML = dirs.length ? dirs.map(d=>`
      <div style="display:flex;align-items:center;gap:10px;padding:8px 0;border-bottom:1px solid var(--border);">
        <div style="width:34px;height:34px;border-radius:50%;background:linear-gradient(135deg,var(--blue),var(--blue-l));display:grid;place-items:center;font-family:'Cinzel',serif;font-weight:700;font-size:13px;flex-shrink:0;">${ini(d.name)}</div>
        <div><div style="font-size:13.5px;font-weight:600;">${esc(d.name)}</div><div style="font-size:11px;color:var(--muted);">${roleLabel(d.role)}</div></div>
      </div>`).join('') : '<p style="color:var(--muted);font-size:13px;">Hakuna wasimamizi bado.</p>';
  }
  // Stats
  const sEl = document.getElementById('about-stats'); if(sEl) {
    sEl.innerHTML = [
      ['👥','Wasimamizi',db.directors.length],
      ['🎵','Nyimbo Zilizohifadhiwa',db.scores.length],
      ['📄','Mwongozo Ulioundwa',db.massOrders.length],
      ['📢','Matangazo',db.announcements.length],
      ['💬','Ujumbe wa Kikundi',db.groupMessages.length],
    ].map(([ic,lbl,val])=>`<div style="display:flex;align-items:center;gap:10px;padding:8px 0;border-bottom:1px solid var(--border);"><span style="font-size:18px;">${ic}</span><span style="color:var(--muted);font-size:13px;flex:1;">${lbl}</span><span style="font-size:15px;font-weight:700;color:var(--gold-l);">${val}</span></div>`).join('');
  }
  // Owner: show add director button
  if ($user.isOwner || $user.role==='owner' || $user.role==='chief') {
    const aboutContent = document.querySelector('.about-content');
    if (aboutContent && !document.getElementById('add-dir-btn')) {
      const btn = document.createElement('button');
      btn.id = 'add-dir-btn';
      btn.className = 'btn btn-blue';
      btn.textContent = '+ Ongeza Msimamizi';
      btn.style.marginTop = '16px';
      btn.onclick = () => openModal('modal-add-director');
      aboutContent.appendChild(btn);
    }
  }
}

/* ─────────────────────────────────────────────────────
   ADD DIRECTOR (owner only)
───────────────────────────────────────────────────── */
function doAddDirector() {
  const name  = document.getElementById('nd-name').value.trim();
  const uname = document.getElementById('nd-username').value.trim();
  const pw    = document.getElementById('nd-pw').value;
  const role  = document.getElementById('nd-role').value;
  const voice = document.getElementById('nd-voice').value;
  const phone = document.getElementById('nd-phone').value.trim();
  const err   = document.getElementById('nd-err');
  err.textContent='';
  if (!name)  return err.textContent='Weka jina kamili.';
  if (!uname) return err.textContent='Weka jina la mtumiaji.';
  if (!pw || pw.length < 4) return err.textContent='Neno la siri liwe na herufi 4+.';
  const db = DB.get();
  if (db.directors.find(d=>d.username?.toLowerCase()===uname.toLowerCase())) return err.textContent='Jina hilo la mtumiaji lipo tayari.';
  DB.update(d => {
    d.directors.push({ uid:'dir_'+Date.now(), name, username:uname, password:pw, role, voice, phone, addedAt:Date.now(), addedBy:$user.name, lastSeen:null, online:false });
  });
  closeModal('modal-add-director');
  ['nd-name','nd-username','nd-pw','nd-phone'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
  DB.logActivity(`${$user.name} aliongeza msimamizi: "${name}"`, '👤', $user.uid);
  toast(`${name} ameongezwa!`); updateStats(); renderAbout();
}

