/* ─── LOAD POSTER DRAFT ─── */
function loadPosterDraft() {
  try {
    const raw = localStorage.getItem('uecsa_poster_draft_v2');
    if (!raw) return;
    const d = JSON.parse(raw);
    Object.entries(d.vals || {}).forEach(([id, v]) => {
      const el = document.getElementById(id);
      if (el) el.value = v;
    });
    // Update overlay label
    const sliderLbl = document.getElementById('overlay-val-lbl');
    const slider = document.getElementById('overlay-slider');
    if (sliderLbl && slider) sliderLbl.textContent = slider.value + '%';
    // Restore bg preset
    if (d.bgIdx !== undefined) {
      $bgPresetIdx = d.bgIdx;
      document.querySelectorAll('.bg-swatch').forEach((b, i) => b.classList.toggle('active', i === d.bgIdx));
    }
    // Restore overlay
    if (d.ovIdx !== undefined) {
      $overlayIdx = d.ovIdx;
      document.querySelectorAll('.theme-swatch').forEach((s, i) => s.classList.toggle('active', i === d.ovIdx));
    }
    // Restore songs
    if (d.songs) {
      d.songs.forEach(s => {
        s.subs.forEach((sub, j) => {
          if (j > 0 && sub.n) {
            addSubSong(s.id);
          }
          const nEl = document.getElementById(`sn-${s.id}-${j}`);
          const kEl = document.getElementById(`sk-${s.id}-${j}`);
          if (nEl) nEl.value = sub.n || '';
          if (kEl) kEl.value = sub.k || '';
        });
      });
    }
    // Restore conductors
    if (d.conds) {
      [1,2,3].forEach(m => {
        (d.conds[m] || []).forEach(name => {
          addCond(m);
          const count = $condCountsEditor[m];
          const inp = document.getElementById(`cname-${m}-${count}`);
          if (inp) inp.value = name;
        });
      });
    }
    renderPoster();
  } catch(e) {
    console.log('[UECSA] Draft load error:', e.message);
  }
}

