/* ─── NOTIFICATIONS UPDATE ─── */
function updateNotifBadge() {
  const db = DB.get();
  const count = db.announcements.filter(a => {
    const diff = Date.now() - a.createdAt;
    return diff < 24 * 60 * 60 * 1000;
  }).length;
  const badge = document.getElementById('notif-count');
  if (badge) {
    badge.style.display = count > 0 ? '' : 'none';
    badge.textContent = count;
  }
}

/* ─── CHAT UNREAD BADGE ─── */
function updateChatBadge() {
  const db = DB.get();
  const myUid = $user?.uid;
  const unread = db.groupMessages.filter(m => m.uid !== myUid).length;
  const badge = document.getElementById('chat-badge');
  if (badge) {
    badge.style.display = unread > 0 ? '' : 'none';
    badge.textContent = unread;
  }
}

/* ─── CLOSE MODAL ON BG CLICK ─── */
document.addEventListener('click', e => {
  if (e.target.classList.contains('modal-bg')) {
    e.target.classList.remove('open');
  }
  // Close notif panel if clicking outside
  const panel = document.getElementById('notif-panel');
  const notifBtn = document.getElementById('tb-notif');
  if (panel && !panel.contains(e.target) && !notifBtn?.contains(e.target)) {
    panel.style.display = 'none';
  }
});

/* ─── KEYBOARD SHORTCUTS ─── */
document.addEventListener('keydown', e => {
  if (e.key === 'Escape') {
    document.querySelectorAll('.modal-bg.open').forEach(m => m.classList.remove('open'));
    document.getElementById('notif-panel').style.display = 'none';
  }
});

