  const col = getSeasonColour();
  const occEl = document.getElementById('pr-occasion');
  if (occEl) occEl.style.color = col.accent;
  const seasonRow = document.getElementById('pr-season-row');
  if (seasonRow) seasonRow.style.color = col.accent;
