/* doAddDir */
function doAddDir() {
  const name  = document.getElementById('nd-name')?.value.trim();
  const uname = document.getElementById('nd-uname')?.value.trim();
  const pw    = document.getElementById('nd-pw')?.value || '';
  const role  = document.getElementById('nd-role')?.value || 'director';
  const voice = document.getElementById('nd-voice')?.value || '';
  const phone = document.getElementById('nd-phone')?.value.trim() || '';
  const err   = document.getElementById('nd-err');
  if (err) err.textContent = '';
  if (!name)  return err && (err.textContent = 'Weka jina kamili.');
  if (!uname) return err && (err.textContent = 'Weka jina la mtumiaji.');
  if (pw.length < 4) return err && (err.textContent = 'Neno la siri liwe na herufi 4+.');
  const db = DB.get();
  if (db.directors.find(d => d.username?.toLowerCase() === uname.toLowerCase()))
    return err && (err.textContent = 'Jina hilo la mtumiaji lipo tayari.');
  DB.update(d => d.directors.push({
    uid: 'dir_'+Date.now(), name, username: uname, password: pw,
    role, voice, phone, addedAt: Date.now(), addedBy: $user.name
  }));
  closeModal('modal-add-dir');
  ['nd-name','nd-uname','nd-pw','nd-phone'].forEach(id => { const e = document.getElementById(id); if(e) e.value=''; });
  DB.log($user.name + ' aliongeza msimamizi: "' + name + '"', '👤');
  buildDirDatalist();
  toast(name + ' ameongezwa! 👤');
  renderAbout();
  updateStatsV3();
}

function delDir(uid, name) {
  if (!confirm('Futa "' + name + '" kutoka kwaya?')) return;
  DB.update(d => { d.directors = d.directors.filter(x => x.uid !== uid); });
  DB.log($user.name + ' alifuta: "' + name + '"', '🗑️');
  toast(name + ' amefutwa.', 'info');
  renderAbout();
  updateStatsV3();
}

/* sendMsg — alias for chat */
function sendMsg() {
  const inp = document.getElementById('chat-inp');
  const txt = inp?.value.trim(); if (!txt) return;
  inp.value = ''; inp.style.height = 'auto';
  const msg = {id:'m_'+Date.now(), uid:$user.uid, name:$user.name, text:txt, ts:Date.now()};
  const db = DB.get();
  if ($currentChat === 'group' || !$activeConv || $activeConv === 'group') {
    DB.update(d => {
      if (!d.groupChat) d.groupChat = [];
      d.groupChat.push(msg);
      if (d.groupChat.length > 500) d.groupChat.shift();
    });
    const prev = document.getElementById('gc-last-msg'); if (prev) prev.textContent = txt;
  } else {
    const key = [$user.uid, $activeConv || $currentChat].sort().join('__');
    DB.update(d => { if (!d.dms) d.dms = {}; if (!d.dms[key]) d.dms[key] = []; d.dms[key].push(msg); });
  }
  renderCurrentChat();
}

function renderCurrentChat() {
  const thread = $activeConv || $currentChat || 'group';
  const db = DB.get();
  const msgs = thread === 'group'
    ? (db.groupChat || db.groupMessages || [])
    : ((db.dms||{})[[$user.uid, thread].sort().join('__')] || []);
  const el = document.getElementById('chat-msgs'); if (!el) return;
  if (!msgs.length) {
    el.innerHTML = '<div class="chat-empty">Hakuna ujumbe bado. Anza mazungumzo! 🎵</div>';
    return;
  }
  const atBot = el.scrollHeight - el.clientHeight - el.scrollTop < 30;
  el.innerHTML = msgs.map(m => {
    const out = m.uid === $user.uid;
    return `<div class="msg-wrap ${out?'out':'in'}">
      ${!out ? `<div class="msg-name">${esc(m.name)}</div>` : ''}
      <div class="msg-bubble ${out?'msg-out':'msg-in'}">${esc(m.text)}</div>
      <div class="msg-time">${fmtTime(m.ts||m.sentAt?.seconds*1000)}</div>
    </div>`;
  }).join('');
  if (atBot || msgs.length <= 20) el.scrollTop = el.scrollHeight;
}

/* Chat view functions for new IDs */
function showGroupChat() {
  $currentChat = 'group'; $activeConv = 'group';
  document.querySelectorAll('.cs-item').forEach(i => i.classList.remove('active'));
  document.getElementById('cs-group')?.classList.add('active');
  const db = DB.get();
  const hav = document.getElementById('ch-av');
  if (hav) { hav.textContent = 'K'; hav.style.background = 'linear-gradient(135deg,var(--green),var(--green3))'; }
  const chn = document.getElementById('ch-name'); if (chn) chn.textContent = 'Kikundi — Wasimamizi Wote';
  const chs = document.getElementById('ch-sub');  if (chs) chs.textContent = db.directors.length + ' wasimamizi';
  renderCurrentChat();
}

function showDM(uid, name) {
  $activeConv = uid; $currentChat = uid;
  document.querySelectorAll('.cs-item').forEach(i => i.classList.remove('active'));
  document.getElementById('cs-'+uid)?.classList.add('active');
  const hav = document.getElementById('ch-av');
  if (hav) { hav.textContent = ini(name); hav.style.background = 'linear-gradient(135deg,var(--blue),var(--blue2))'; }
  const chn = document.getElementById('ch-name'); if (chn) chn.textContent = name;
  const db = DB.get(); const dir = db.directors.find(d => d.uid === uid);
  const chs = document.getElementById('ch-sub');  if (chs) chs.textContent = dir ? roleName(dir.role) : 'Msimamizi';
  renderCurrentChat();
}

function buildDMList() {
  const el = document.getElementById('dm-list'); if (!el) return;
  const db = DB.get();
  el.innerHTML = db.directors.filter(d => d.uid !== $user?.uid).map(d => `
    <div class="cs-item" id="cs-${d.uid}" onclick="showDM('${d.uid}','${esc(d.name)}')">
      <div class="cs-av" style="background:linear-gradient(135deg,var(--blue),var(--blue2))">${ini(d.name)}</div>
      <div class="cs-info">
        <div class="cs-name">${esc(d.name)}</div>
        <div class="cs-preview">${roleName(d.role)}</div>
      </div>
    </div>`).join('');
}

function initChat() { buildDMList(); showGroupChat(); }
function refreshChat() { renderCurrentChat(); }

/* Announcements for new IDs */
function renderAnn() {
  const db = DB.get();
  const el = document.getElementById('ann-list-items'); if (!el) return;
  const isLead = $user?.isOwner || ['owner','chief','deputy'].includes($user?.role);
  const TYPE_IC = {general:'📋', rehearsal:'🎵', urgent:'🚨', event:'🎉'};
  if (!db.announcements.length) {
    el.innerHTML = '<div class="empty"><span class="ei">📢</span><p>Hakuna matangazo bado.</p></div>';
    return;
  }
  el.innerHTML = db.announcements.map((a, i) => `
    <div class="ann-card ann-${a.type||'general'}" style="animation-delay:${i*.05}s">
      <div class="ann-head">
        <span class="ann-type-ic">${TYPE_IC[a.type]||'📋'}</span>
        <div class="ann-title">${esc(a.title)}</div>
        ${isLead ? `<button class="ann-del" onclick="delAnn('${a.id}')">✕</button>` : ''}
      </div>
      <div class="ann-body">${esc(a.body)}</div>
      <div class="ann-meta">
        <span>— ${esc(a.by)}</span>
        <span>${timeAgo(a.createdAt)}</span>
        <span style="background:rgba(255,255,255,.06);padding:2px 8px;border-radius:10px;font-size:10px;">${a.type||'general'}</span>
      </div>
    </div>`).join('');
}

function doPostAnn() {
  const title = document.getElementById('ann-title')?.value.trim();
  const body  = document.getElementById('ann-body')?.value.trim();
  const type  = document.getElementById('ann-type')?.value || 'general';
  const err   = document.getElementById('ann-err');
  if (err) err.textContent = '';
  if (!title) return err && (err.textContent = 'Weka kichwa cha habari.');
  if (!body)  return err && (err.textContent = 'Weka ujumbe.');
  DB.update(d => d.announcements.unshift({
    id: 'ann_'+Date.now(), title, body, type,
    by: $user.name, byUid: $user.uid, createdAt: Date.now()
  }));
  closeModal('modal-ann');
  const ti = document.getElementById('ann-title'); if (ti) ti.value = '';
  const bi = document.getElementById('ann-body');  if (bi) bi.value = '';
  DB.log($user.name + ' alituma tangazo: "' + title + '"', '📢');
  toast('Tangazo limetumwa! 📢');
  renderAnn(); renderHomeAnns(); renderNotifs(); updateStatsV3();
  const b = document.getElementById('ann-badge');
  if (b) { b.style.display = ''; b.textContent = '!'; }
}

function delAnn(id) {
  if (!confirm('Futa tangazo hili?')) return;
  DB.update(d => { d.announcements = d.announcements.filter(a => a.id !== id); });
  toast('Tangazo limefutwa.', 'info'); renderAnn(); updateStatsV3();
}

/* BG + Logo file handlers */
function onBgDrop(e) {
  e.preventDefault(); document.getElementById('bg-drop')?.classList.remove('drag');
  const f = e.dataTransfer.files[0];
  if (f?.type.startsWith('image/')) readBgFile(f);
}
function onBgFile(inp) { if (inp.files[0]) readBgFile(inp.files[0]); }
function readBgFile(f) {
  const r = new FileReader();
  r.onload = e => {
    $bgCustomData = e.target.result;
    const c = document.getElementById('bg-chosen'); if (c) c.textContent = '✓ ' + f.name;
    document.querySelectorAll('.swatch').forEach(s => s.classList.remove('on'));
    renderPoster();
  };
  r.readAsDataURL(f);
}
function onLogoFile(inp, n) {
  if (!inp.files[0]) return;
  const r = new FileReader();
  r.onload = e => {
    const data = e.target.result;
    if (n === 1) {
      $logo1Data = data;
      const prev = document.getElementById('logo1-prev');
      if (prev) prev.innerHTML = '<img src="' + data + '" style="max-height:46px;max-width:100%;object-fit:contain;" alt="L1"/>';
    } else {
      $logo2Data = data;
      const prev = document.getElementById('logo2-prev');
      if (prev) prev.innerHTML = '<img src="' + data + '" style="max-height:46px;max-width:100%;object-fit:contain;" alt="L2"/>';
    }
    updatePosterLogoDefaults();
    renderPoster();
  };
  r.readAsDataURL(inp.files[0]);
}

/* Score PDF handlers */
function onScorePdfDrop(e) {
  e.preventDefault(); document.getElementById('score-dz')?.classList.remove('over');
  const f = e.dataTransfer.files[0];
  if (f?.type === 'application/pdf') { $pdfFile = f; const l = document.getElementById('score-pdf-lbl'); if(l) l.textContent = '✓ ' + f.name; }
}
function onScorePdfFile(inp) {
  if (inp.files[0]) { $pdfFile = inp.files[0]; const l = document.getElementById('score-pdf-lbl'); if(l) l.textContent = '✓ ' + inp.files[0].name; }
}

/* Poster social update (pr-social-wrap) */
function updatePosterSocial(tt, yt, ph, phr) {
  const sw = document.getElementById('pr-social-wrap');
  const items = [];
  if (tt) items.push('<span class="pr-soc-item">♪ TikTok: ' + esc(tt) + '</span>');
  if (yt) items.push('<span class="pr-soc-item">▶ Youtube: ' + esc(yt) + '</span>');
  if (ph) items.push('<span class="pr-soc-item">📞 ' + esc(ph) + (phr ? ' <span style="font-size:7pt">' + esc(phr) + '</span>' : '') + '</span>');
  if (sw) {
    if (items.length) {
      sw.style.display = 'flex';
      sw.innerHTML = '<div style="width:100%;text-align:center;"><span class="pr-social-header">Tufuate kwenye mitandao ya kijamii</span><div class="pr-social">' + items.join('') + '</div></div>';
    } else { sw.style.display = 'none'; }
  }
}

/* renderHome — full version */
function renderHome() {
  updateStatsV3();
  renderHomeAnns();
  if ($user?.isOwner || ['owner','chief'].includes($user?.role)) {
    renderActivity();
    const oas = document.getElementById('owner-activity-section');
    if (oas) oas.style.display = '';
  }
  renderNotifs();
}

/* renderScores */
function renderScores() { populateScoreSelects(); filterScores(); }

/* populateScoreSelects — fills key and type selects */
function populateScoreSelects() {
  const db = DB.get();
  ['sc-key','scores-key-filter'].forEach(id => {
    const el = document.getElementById(id);
    if (el && el.options.length <= 1) MUSICAL_KEYS.forEach(k => { const o = document.createElement('option'); o.value = o.textContent = k; el.appendChild(o); });
  });
  ['sc-type','scores-type-filter'].forEach(id => {
    const el = document.getElementById(id);
    if (el && el.options.length <= 1) SONG_TYPES.forEach(t => { const o = document.createElement('option'); o.value = o.textContent = t; el.appendChild(o); });
  });
}

/* switchView — override to call right render functions */
const _origSwitchView = switchView;
function switchView(id) {
  document.querySelectorAll('.view').forEach(v => v.classList.remove('active-view'));
  const el = document.getElementById('view-' + id); if (el) el.classList.add('active-view');
  $currentView = id;
  document.querySelector('.dash-body')?.scrollTo(0, 0);
  const renders = {
    home: renderHome,
    scores: renderScores,
    announcements: renderAnn,
    chat: initChat,
    about: renderAbout,
  };
  if (renders[id]) renders[id]();
}

/* setupDashboard — override to handle new HTML */
const _origSetupDash = setupDashboard;
function setupDashboard() {
  const me = $user;
  const av = document.getElementById('tb-av'); if (av) av.textContent = ini(me.name);
  setElText('tb-uname', me.name);
  setElText('tb-urole', roleLabel(me.role));
  const tl = document.getElementById('tb-logo-img'); if (tl) tl.src = LOGO_CSA;

  const hr = new Date().getHours();
  const greet = hr < 12 ? 'Habari za asubuhi' : hr < 17 ? 'Habari za mchana' : 'Habari za jioni';
  setElText('hw-greet', greet + ', ' + me.name.split(' ')[0] + '.');
  setElText('hw-sub', 'Karibu kwenye Mfumo wa Wasimamizi wa Kwaya.');
  const now = new Date();
  setElText('hw-day', now.getDate());
  setElText('hw-month', now.toLocaleDateString('sw-KE', {month:'long',year:'numeric'}));

  const isLead = me.isOwner || ['owner','chief','deputy'].includes(me.role);
  if (isLead) {
    const fab = document.getElementById('owner-fab'); if (fab) fab.style.display = 'grid';
    const oas = document.getElementById('owner-activity-section'); if (oas) oas.style.display = '';
    const aa  = document.getElementById('ann-actions'); if (aa) aa.style.display = 'flex';
  } else {
    const aa = document.getElementById('ann-actions'); if (aa) aa.style.display = 'none';
  }

  updateStatsV3();
  initPosterEditor();
  loadPosterDraft();
  populateScoreSelects();
  buildDirDatalist();
  AI.load();

  clearInterval($gcInterval);
  $gcInterval = setInterval(() => {
    if ($currentView === 'chat') renderCurrentChat();
    if ($currentView === 'home') updateStatsV3();
  }, 2500);

  switchView('home');
}

/* Override afterLogin to call new setupDashboard */
function afterLogin() {
  DB.logActivity($user.name + ' ameingia', '🔐', $user.uid);
  setupDashboard();
  showPage('dashboard');
  const btn = document.getElementById('btn-login');
  if (btn) { btn.disabled = false; const t = document.getElementById('btn-login-txt'); if(t) t.textContent = 'Ingia'; }
}

